// Query all configured Netdata hosts in parallel
const hostString = process.env.NETDATA_HOSTS || '';
if (!hostString) return [{ json: { alerts: ['NETDATA_HOSTS not configured'], isCritical: false } }];

const hosts = {};
hostString.split(',').forEach(h => {
  const colonIdx = h.indexOf(':http');
  if (colonIdx > 0) {
    const name = h.slice(0, colonIdx).trim();
    const url  = 'http' + h.slice(colonIdx + 1).trim();
    hosts[name] = url;
  }
});

const THRESHOLDS = {
  cpu:    85,  // %
  ram:    90,  // %
  disk:   85,  // %
  uptime: 900  // seconds — flag if uptime < 15min (recently rebooted)
};

const alerts = [];

await Promise.all(Object.entries(hosts).map(async ([name, baseUrl]) => {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/api/v1/allmetrics?format=json`,
      timeout: 8000
    });
    const d = typeof resp === 'string' ? JSON.parse(resp) : resp;

    // CPU
    const cpuIdle = d?.['system.cpu']?.dimensions?.idle?.value;
    if (cpuIdle !== undefined) {
      const cpuUsed = 100 - cpuIdle;
      if (cpuUsed > THRESHOLDS.cpu) alerts.push(`⚠️ ${name}: CPU ${cpuUsed.toFixed(1)}% (threshold ${THRESHOLDS.cpu}%)`);
    }

    // RAM
    const ramUsed = d?.['system.ram']?.dimensions?.used?.value;
    const ramFree = d?.['system.ram']?.dimensions?.free?.value;
    const ramBuff = (d?.['system.ram']?.dimensions?.buffers?.value || 0) + (d?.['system.ram']?.dimensions?.cached?.value || 0);
    if (ramUsed !== undefined && ramFree !== undefined) {
      const total = ramUsed + ramFree + ramBuff;
      const pct   = total > 0 ? (ramUsed / total) * 100 : 0;
      if (pct > THRESHOLDS.ram) alerts.push(`⚠️ ${name}: RAM ${pct.toFixed(1)}% used (threshold ${THRESHOLDS.ram}%)`);
    }

    // Uptime
    const uptime = d?.['system.uptime']?.dimensions?.uptime?.value;
    if (uptime !== undefined && uptime < THRESHOLDS.uptime) {
      alerts.push(`🔔 ${name}: recently rebooted (uptime ${Math.round(uptime / 60)} min)`);
    }

  } catch (err) {
    alerts.push(`🔴 ${name}: unreachable — ${err.message}`);
  }
}));

// UPS check
try {
  const net = require('net');
  const UPS_HOST = process.env.UPS_HOST;
  const UPS_PORT = parseInt(process.env.UPS_PORT || '3551');
  if (UPS_HOST) {
    const upsRaw = await new Promise((resolve, reject) => {
      const client = net.createConnection(UPS_PORT, UPS_HOST, () => {
        const cmd = Buffer.alloc(8);
        cmd.writeUInt16BE(6, 0);
        cmd.write('status', 2);
        client.write(cmd);
      });
      let data = Buffer.alloc(0);
      client.on('data', c => { data = Buffer.concat([data, c]); });
      client.on('end', () => resolve(data.toString('ascii')));
      client.on('error', reject);
      setTimeout(() => { client.destroy(); reject(new Error('timeout')); }, 5000);
    });
    const kv = {};
    upsRaw.split('\n').forEach(line => {
      const i = line.indexOf(':');
      if (i > 0) kv[line.slice(0, i).trim()] = line.slice(i + 1).trim();
    });
    const status  = kv['STATUS']  || '';
    const bcharge = parseFloat(kv['BCHARGE'] || '100');
    if (status.includes('ONBATT')) {
      alerts.push(`🔴 UPS ON BATTERY — battery ${bcharge}%`);
    } else if (bcharge < 30) {
      alerts.push(`🔴 UPS battery critically low: ${bcharge}%`);
    }
  }
} catch (err) {
  // UPS check failure is not itself an alert — host may not have UPS
}

const isCritical = alerts.some(a =>
  a.includes('ON BATTERY') ||
  a.includes('battery critically low') ||
  a.includes('unreachable')
);

return [{ json: { alerts, isCritical, alertCount: alerts.length } }];

// Alert deduplication — suppress repeated identical alerts within the cooldown window.
// State persists across executions via $workflow.staticData (n8n built-in per-workflow KV).
//
// Cooldown window: ALERT_DEDUP_MINUTES env var (default 30 minutes).
// Critical alerts bypass dedup — they always fire.
const alerts     = $input.first().json.alerts;
const isCritical = $input.first().json.isCritical;
const alertCount = $input.first().json.alertCount;

const COOLDOWN_MS   = parseInt(process.env.ALERT_DEDUP_MINUTES || '30') * 60 * 1000;
const fingerprint   = [...alerts].sort().join('|');
const state         = $workflow.staticData;
const now           = Date.now();

const sameFingerprint = state.lastFingerprint === fingerprint;
const withinCooldown  = state.lastSentAt && (now - state.lastSentAt) < COOLDOWN_MS;

if (!isCritical && sameFingerprint && withinCooldown) {
  // Identical non-critical alerts already sent within the cooldown window — suppress
  return [];
}

// New, changed, or critical alerts — update state and pass through
state.lastFingerprint = fingerprint;
state.lastSentAt      = now;

return [{ json: { alerts, isCritical, alertCount } }];

// Summarize alerts with Ollama (containy.galaxy)
// Falls back gracefully if Ollama is unavailable.
const alerts = $input.first().json.alerts;
const isCritical = $input.first().json.isCritical;
const alertCount = $input.first().json.alertCount;

const ollamaUrl = process.env.OLLAMA_URL_CONTAINY || 'http://containy.galaxy:11434';
const model = process.env.OLLAMA_MODEL || 'llama3.2:3b';

const prompt = `You are NOLA, a homelab monitoring assistant. Summarize these infrastructure alerts in 1-2 sentences. Be direct and technical — provide insight or context, do not just repeat the raw data verbatim.\n\nAlerts:\n${alerts.join('\n')}`;

let aiSummary = null;
try {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: `${ollamaUrl}/api/generate`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model, prompt, stream: false }),
    timeout: 15000
  });
  const data = typeof resp === 'string' ? JSON.parse(resp) : resp;
  aiSummary = data?.response?.trim() || null;
} catch (err) {
  // Ollama unavailable — continue without AI summary
}

return [{ json: { alerts, isCritical, alertCount, aiSummary } }];

